effect.shader:
void main() {
    int from = -max(1,int(strength));
    int to = max(1,int(strength));
    vec4 outColor = vec4(0.0);
    for(int i=from; i<to; i++ ) {
        vec4 texColor = texture2DCv(inputImg.texture,vec2(acScreenNorm.s + float(i)*(1.0/1280.0),acScreenNorm.t));
        //lowp float r = texColor.r;
        //lowp float g = texColor.g;
        //lowp float b = texColor.b;
        outColor += texColor;
    }
    gl_FragColor = outColor/(float(to)*2.0);
}
